import{_ as a}from"./Menu.179edc93.js";import{u as n}from"./composables.96d18f89.js";import{r as e,a as l,e as o,b as p,f as s,o as u}from"./entry.7b9f66e3.js";const c=""+new URL("article-design-ui-process-e2.3d29fc57.jpg",import.meta.url).href,d={class:"banniere"},m=s('<div class="margium-l marge-haute-l"><div class="espacium"><div class="colonnes"><div class="colonne"><h1>Le Processus UI</h1><div class="projettitre"></div> 20 septembre 2022 \xB7 2 min </div><div class="colonne"></div></div></div></div>',1),v=s('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p> L&#39;\xE9tape du design d&#39;interface est une partie importante dans la conception, c&#39;est l\xE0 que le projet prend forme. Il fait aussi l&#39;objet de nombreuses passations : entre l&#39;\xE9quipe de recherche UX, entre le client puis avec les d\xE9veloppeurs. Et qui dit transmission, dit rigueur pour \xE9viter la perte d&#39;informations et les retours en arri\xE8re. </p><h2>1<span class="est-mauve">.</span> Rassembler les inputs</h2><p class="sans-espacement"> Les inputs des projets traditionnels : <ul><li>Le cahier des charges</li><li>Les diff\xE9rents courriels \xE9chang\xE9s depuis</li><li>L&#39;ancien site (dans le cas d&#39;une refonte)</li><li>Un benchmark du secteur</li></ul></p><p class="sans-espacement"> Dans les projets plus ax\xE9s sur de la recherche UX et design thinking, les inputs sont : <ul><li>Les wireflows</li><li>Les synth\xE8ses des ateliers de co-conception / design studio</li><li>Les Exp\xE9riences Map</li><li>Un benchmark UX</li><li>Un document de sp\xE9cification technique issue d&#39;une <abbr title="Assistance \xE0 Ma\xEEtrise d\u2019Ouvrage ">AMOA</abbr></li></ul></p><p>Rassemblez-les dans une page Figma ou Miro, n&#39;h\xE9sitez pas \xE0 les d\xE9couper, \xE0 les r\xE9-organiser et \xE0 les surligner pour mieux vous les approprier.</p><h2>2<span class="est-mauve">.</span> Dessiner les wireframes</h2><p>Quitter votre clavier et votre souris, vous n&#39;en aurais pas besoin pour les wireframes, il est recommand\xE9 de les faire \xE0 la main sans outils contraignants. N&#39;utilisez pas non plus de canvas de t\xE9l\xE9phone pr\xEAt \xE0 imprimer ou de r\xE8gle pour tracer de ligne droite, c&#39;est un exercice d&#39;id\xE9ation ! Prenez simplement une feuille blanche et un feutre 0.5\u2009mm noir pour pouvoir \xEAtre bien visible lorsque les wireframes seront scann\xE9s. </p><img src="'+c+'" loading="lazy" alt="Wireframe"><h2>3<span class="est-mauve">.</span> UI Kit et composants</h2><p><ul><li><b>Choisissez vos tailles de pages</b>, les plus fr\xE9quents sont 1440x1024 pour desktop et 390x844 pour le mobile (iphone 12/13). </li><li><b>D\xE9finissez la grille de votre maquette</b>, 12 colonnes avec des marges de 100px et des goutti\xE8res de 20px. Pour le mobile, 4 colonnes, des marges de 25px et des goutti\xE8res de 5px.</li><li><b>Identifiez les diff\xE9rents \xE9l\xE9ments</b> de votre wireframes et commencez votre <b>UI Kit</b> : <br> Style des titres, textes, couleurs et \xE9l\xE9ment (check box, input text, bouton...) <br>N&#39;h\xE9sitez pas \xE0 cr\xE9er des <b>variants</b> et utiliser de <b>l&#39;auto-layout</b> pour gagner du temps sur la mise en place sur les maquettes. </li><li>Cr\xE9er vos <b>composants</b> en utilisant votre UI Kit : <br> Header, footer, menu, card, blocs sp\xE9cifiques\u2026</li></ul></p><h2>4<span class="est-mauve">.</span> Maquettage</h2><p>Reprenez-les wireframes en utilisant vos composants et votre UI Kit pour cr\xE9er vos maquettes. Il est fortement recommand\xE9 d&#39;utiliser <b>l&#39;auto-layout</b> pour g\xE9rer <b>l&#39;espacement vertical</b> de votre page, cela permet d&#39;intervertir facilement vos sections mais principalement prendre en compte les contraintes d&#39;int\xE9gration web (css, flexbox). Pour une bonne harmonie, utilisez les <b>multiples de 8</b> pour vos espacements : 16px, 32px, 40px, 64px, 72px, 96px... <br>Il est essentiel de passer les maquettes en revue avec les crit\xE8res d\u2019accessibilit\xE9 de la <abbr title="r\xE9f\xE9rentiel g\xE9n\xE9ral d\u2019am\xE9lioration de l\u2019accessibilit\xE9">RGAA</abbr>. Les corrections des probl\xE8mes d\u2019accessibilit\xE9s sont plus facile \xE0 r\xE9gler en amont qu&#39;en aval du d\xE9veloppement.<br></p><h2>6<span class="est-mauve">.</span> Validation par le commanditaire</h2><p class="sans-espacement">Avant de partir en production, les maquettes doivent \xEAtre valid\xE9es par le commanditaire, ce processus peut s\u2019av\xE9rer long :</p><ul><li>Retours tardifs</li><li>Commentaires contradictoires de la part des diff\xE9rentes parties prenantes</li><li>Retours en arri\xE8re r\xE9currents</li><li>Les reports de d\xE9cisions</li></ul><p> Pour \xE9viter ces situations bloquantes et garder une fluidit\xE9 dans le projet, il faut r\xE9unir toutes les parties prenantes commanditaires et mener une r\xE9union de discussions et validation des maquettes. L&#39;occasion de mettre en valeur les solutions choisies par les designers, d&#39;\xE9changer, d&#39;\xE9couter et de trancher ou de lancer une phase de test utilisateurs si le projet le permet. </p><h2>7<span class="est-mauve">.</span> Notes pour les d\xE9veloppeurs</h2><p>Un certain nombre d&#39;informations sur les \xE9l\xE9ments sont d\xE9j\xE0 document\xE9es automatiquement dans le projet Figma pour aider les d\xE9veloppeurs dans l&#39;int\xE9gration et le d\xE9veloppement des pages. Toutefois, certains \xE9l\xE9ments n\xE9cessitent plus de pr\xE9cisions : quel est le comportement du menu (aux cliques ou au survol...), les fonctionnalit\xE9s des champs (auto-compl\xE9tion, option des champs textes, contenu des liste d\xE9roulantes...)</p></div></div></article>',1),q={__name:"le-processus-ui",setup(b){const t=e("Le Processus UI - Lucas Lacroix"),i=e("L'\xE9tape du design d'interface est une partie importante dans la conception, c'est l\xE0 que le projet prend forme. Il fait aussi l'objet de nombreuses passations : entre l'\xE9quipe de recherche UX, entre le client puis avec les d\xE9veloppeurs.");return n({title:t,meta:[{name:"description",content:i}]}),(f,h)=>{const r=a;return u(),l("div",null,[o("div",d,[p(r),m]),v])}}};export{q as default};
